"use client";

import React, { useState } from 'react';

// --- Cryptographic Helper for Web Push ---
// The browser's PushManager requires the VAPID public key to be converted into a Uint8Array.
function urlBase64ToUint8Array(base64String: string) {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding).replace(/\-/g, '+').replace(/_/g, '/');
  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

const mockPageBinding = {
  seriesKey: "ssa-ssdi-payments",
  canonicalName: "Social Security Disability Insurance (SSDI) Payments",
  entityName: "Social Security Administration",
  generatedAtUtc: "2026-03-04T00:00:00Z",
  binding: {
    isCollapsed: false,
    scoreIdentityTuple: { verdict: "PASS", trustScore: 99, citeabilityScore: 98, tupleHash: "sha256:dummy" }
  },
  distributionBinding: { windowModel: "DAY_OF_YEAR", n: 24, p10: 3, p50: 3, p90: 4 },
  latestRecordBinding: { id: "ssdi-payment-march-2026" },
  derivedClaims: [
    "Historically, SSDI payments occur on the 3rd of the month.",
    "Method: HISTORICAL_DISTRIBUTION_ONLY. Statistics summarize observed past occurrences."
  ],
  refs: { seriesUrl: "https://whenisdue.com/series/ssa-ssdi-payments" }
};

export default function SeriesPage({ params }: { params: { seriesKey: string } }) {
  const isPass = mockPageBinding.binding.scoreIdentityTuple?.verdict === "PASS";
  
  // State to manage button UI
  const [subStatus, setSubStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');

  // --- The Core Web Push Subscription Logic ---
  const handleSubscribe = async () => {
    setSubStatus('loading');
    try {
      // 1. Check if the browser supports Service Workers and Web Push
      if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
        alert('Web Push is not supported in this browser. Try Chrome or Safari.');
        setSubStatus('error');
        return;
      }

      // 2. Register the background listener (sw.js)
      const registration = await navigator.serviceWorker.register('/sw.js');
      await navigator.serviceWorker.ready;

      // 3. Grab the VAPID key from our .env.local file
      const vapidPublicKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
      if (!vapidPublicKey) {
        throw new Error("Missing VAPID Public Key. Check your .env.local file.");
      }

      // 4. Request permission & generate the cryptographic subscription
      const subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(vapidPublicKey),
      });

      // 5. Send the encrypted routing data to our SQLite database via the API
      const response = await fetch('/api/push/subscribe', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(subscription),
      });

      if (!response.ok) {
        throw new Error('Server rejected the subscription payload.');
      }

      setSubStatus('success');
      console.log("Successfully securely saved to SQLite Database!");

    } catch (error) {
      console.error('Subscription failed:', error);
      setSubStatus('error');
    }
  };

  return (
    <main className="max-w-4xl mx-auto p-8 font-sans bg-black min-h-screen text-white">
      <header className="mb-10 border-b border-gray-800 pb-6">
        <h1 className="text-4xl font-extrabold text-white mb-2">{mockPageBinding.canonicalName}</h1>
        <p className="text-lg text-gray-300 mb-4 font-sans">
          Administered by the <span className="font-semibold text-white">{mockPageBinding.entityName}</span>
        </p>
        <div className="flex items-center gap-4">
          <span className={`px-3 py-1 text-sm font-bold rounded ${isPass ? 'bg-green-900 text-green-100' : 'bg-red-900 text-red-100'}`}>
            Trust Verdict: {mockPageBinding.binding.scoreIdentityTuple?.verdict}
          </span>
        </div>
      </header>

      {/* --- Notification Button Section --- */}
      <div style={{ backgroundColor: '#1e3a8a', padding: '20px', borderRadius: '10px', marginBottom: '30px', textAlign: 'center' }}>
        <h2 style={{ color: 'white', margin: '0 0 10px 0' }}>Enable Lock-Screen Alerts</h2>
        <p style={{ color: '#bfdbfe', marginBottom: '20px' }}>Get notified the moment a date is verified.</p>
        
        <button 
          onClick={handleSubscribe}
          disabled={subStatus === 'loading' || subStatus === 'success'}
          style={{ 
            backgroundColor: subStatus === 'success' ? '#10b981' : 'white', 
            color: subStatus === 'success' ? 'white' : '#1e3a8a', 
            padding: '10px 30px', 
            borderRadius: '50px', 
            border: 'none', 
            fontWeight: 'bold', 
            cursor: subStatus === 'success' ? 'default' : 'pointer',
            transition: 'all 0.3s ease'
          }}
        >
          {subStatus === 'idle' && "NOTIFY ME"}
          {subStatus === 'loading' && "SECURING CONNECTION..."}
          {subStatus === 'success' && "✓ SUBSCRIBED"}
          {subStatus === 'error' && "ERROR - TRY AGAIN"}
        </button>
      </div>

      <section>
        <h2 className="text-2xl font-bold text-white mb-4">Verified Past Occurrences</h2>
        <div className="border border-gray-700 rounded-lg overflow-hidden bg-gray-900">
          <table className="w-full text-left">
            <thead className="bg-gray-800 border-b border-gray-700 text-gray-100 text-xs uppercase tracking-wider">
              <tr>
                <th className="p-4">Event Date</th>
                <th className="p-4 text-right">Action</th>
              </tr>
            </thead>
            <tbody>
              <tr className="border-b border-gray-800 hover:bg-gray-800 transition-colors">
                <td className="p-4 text-gray-300 font-mono">2026-03-03</td>
                <td className="p-4 text-right">
                  <span className="inline-block bg-blue-600 text-white text-[10px] font-black py-2 px-4 rounded uppercase tracking-widest">
                    Verify Proof
                  </span>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </section>
    </main>
  );
}